import{_ as t,o as n,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"113. Once Off Retention Payment","description":"","frontmatter":{"title":"113. Once Off Retention Payment","eba":"Mental Health Services 2024-2028","topics":["wages","employment"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/wages/113-once-off-retention-payment.md","filePath":"ebas/mental-health/health-professionals/wages/113-once-off-retention-payment.md"}'),s={name:"ebas/mental-health/health-professionals/wages/113-once-off-retention-payment.md"};function r(l,e,m,i,p,f){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_113-once-off-retention-payment" tabindex="-1">113. Once Off Retention Payment <a class="header-anchor" href="#_113-once-off-retention-payment" aria-label="Permalink to &quot;113. Once Off Retention Payment&quot;">​</a></h1><p><strong>113.1</strong> A Once Off Retention Payment of $4,200 will be paid to full time AHP1 Employees at the commencement of the Agreement.</p><p><strong>113.2</strong> The Once Off Payment will be paid over two instalments as follows:</p><p><strong>(a)</strong> FFPPOA commencement of Agreement - $2,100.</p><p><strong>(b)</strong> Next pay period after 113.2(a) - $2,100.</p><p><strong>113.3</strong> The payments will be paid to part time Employees on a pro rata basis.</p><p><strong>113.4</strong> Casual Employees will receive pro rata payments based on average hours over previous 12 months calculated at the time the Agreement commences.</p>',7)])])}const _=t(s,[["render",r]]);export{h as __pageData,_ as default};
